    public Object parseBalance(Object response)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
        }};
        Object balances = this.safeDict(response, "balances", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object currencies = Helpers.objectKeys(balances);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(currencies)); i++)
        {
            Object code = Helpers.GetValue(currencies, i);
            Object balance = Helpers.GetValue(balances, code);
            Object account = this.account();
            Helpers.addElementToObject(account, "free", this.safeString(balance, "free"));
            Helpers.addElementToObject(account, "used", this.safeString(balance, "used"));
            Helpers.addElementToObject(account, "total", this.safeString(balance, "total"));
            Helpers.addElementToObject(result, code, account);
        }
        Object timestamp = this.safeInteger(response, "timestamp");
        Helpers.addElementToObject(result, "timestamp", timestamp);
        Helpers.addElementToObject(result, "datetime", this.iso8601(timestamp));
        return this.safeBalance(result);
    }

