    /**
     * @method
     * @name aftermath#withdraw
     * @see https://testnet.aftermath.finance/docs/#/CCXT/build_withdraw
     * @see https://testnet.aftermath.finance/docs/#/CCXT/submit_withdraw
     * @description make a withdrawal
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {Account} [params.account] account id to use, required
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object account = null;
            var accountparametersVariable = this.handleOptionAndParams(parameters, "withdraw", "account");
            account = ((java.util.List<Object>) accountparametersVariable).get(0);
            parameters = ((java.util.List<Object>) accountparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(account, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " withdraw() requires a account parameter in params")) ;
            }
            final Object finalAccount = account;
            Object txRequest = new java.util.HashMap<String, Object>() {{
                put( "accountId", finalAccount );
                put( "metadata", new java.util.HashMap<String, Object>() {{
                    put( "sender", AftermathCore.this.walletAddress );
                }} );
                put( "amount", amount );
            }};
            Object tx = (this.privatePostBuildWithdraw(txRequest)).join();
            Object request = this.signTxEd25519(tx);
            Object response = (this.privatePostSubmitWithdraw(request)).join();
            //
            // {
            //     "id": "0xf93f9bb8bf97eb570410caada92cfa3e66c7ed3a203a164f51d22d41eabe09c0",
            //     "type": "subaccount",
            //     "code": "USDC",
            //     "accountNumber": 101,
            //     "collateral": 39.0
            // }
            //
            Object parsedTx = this.parseTransaction(response, currency);
            Helpers.addElementToObject(parsedTx, "addressFrom ", account);
            Helpers.addElementToObject(parsedTx, "amount", amount);
            return parsedTx;
        });

    }

